// lifecycle.ts (conceptual)
export type RestartContext = {
  ...
  previousSessionId?: string;
  originChannel?: 'web' | 'telegram' | 'task' | 'cron' | 'unknown';
  replyToTelegram?: boolean;
};

// boot.ts (conceptual)
const sessionId = resolveBriefingSessionId(restartCtx);
await handleChat(briefingPrompt, sessionId, ...);

if (restartCtx?.replyToTelegram || restartCtx?.originChannel === 'telegram') {
  try {
    await sendTelegramNotification(restartSummary);
  } catch (err) {
    logger.warn('Post-restart Telegram notify failed', err);
  }
}
